import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import api from '../../api/api';
import { useNotifier } from '../../context/NotificationContext';

const Dashboard = () => {
    const { user } = useAuth();
    const { notify } = useNotifier();
    const [isReprofiling, setIsReprofiling] = useState(false);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        // Fetch current bench status
        api.get('/api/v1/workforce/bench?limit=100')
            .then(res => {
                if (res.data.success) {
                    const myBenchStatus = res.data.data.find(b => b.id_employee === user.id);
                    if (myBenchStatus && myBenchStatus.status === 'available') {
                        setIsReprofiling(true);
                    }
                }
            })
            .catch(err => console.error(err))
            .finally(() => setIsLoading(false));
    }, [user.id]);

    const handleReprofileToggle = async (e) => {
        const newValue = e.target.checked;
        setIsReprofiling(newValue);
        
        try {
            const res = await api.patch('/api/v1/workforce/my-bench/reprofile', { is_reprofiling: newValue });
            if (res.data.success) {
                notify({ message: newValue ? 'You are now marked as available for reprofiling.' : 'You have been removed from the reprofiling bench.', style: 'success' });
            } else {
                setIsReprofiling(!newValue);
                notify({ message: 'Failed to update status', style: 'error' });
            }
        } catch (error) {
            setIsReprofiling(!newValue);
            notify({ message: 'An error occurred while updating your status.', style: 'error' });
        }
    };

    return (
        <div className="admin-pager">
            <header className="admin-pager-head">
                <div className="admin-pager-title">
                    <h2>Employee Dashboard</h2>
                    <p>Welcome back, {user.fn}</p>
                </div>
            </header>

            <div className="dashboard-widgets" style={{ display: 'flex', gap: '20px', padding: '20px' }}>
                <div className="widget-card" style={{ flex: 1, backgroundColor: 'var(--box)', padding: '25px', borderRadius: '12px', border: '1px solid var(--bdr)' }}>
                    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '15px' }}>
                        <div>
                            <h3 style={{ margin: '0 0 5px 0' }}>Availability Status</h3>
                            <p style={{ margin: 0, color: 'var(--gray)', fontSize: '0.9em' }}>Let HR know you are available for a new client project.</p>
                        </div>
                        <Icon icon={icons.userCheck} style={{ fontSize: '2em', color: 'var(--primary)' }} />
                    </div>
                    
                    {isLoading ? (
                        <p>Loading status...</p>
                    ) : (
                        <div style={{ display: 'flex', alignItems: 'center', gap: '15px', marginTop: '20px', padding: '15px', backgroundColor: 'var(--bg)', borderRadius: '8px', border: '1px solid var(--bdr)' }}>
                            <label className="toggle-switch">
                                <input type="checkbox" checked={isReprofiling} onChange={handleReprofileToggle} />
                                <span className="slider round"></span>
                            </label>
                            <div>
                                <b style={{ display: 'block' }}>{isReprofiling ? 'Available for Reprofile' : 'Currently Assigned'}</b>
                                <span style={{ fontSize: '0.85em', color: 'var(--gray)' }}>
                                    {isReprofiling ? 'Recruitment and Admins can see you are ready for a new project.' : 'You are currently active on a client project.'}
                                </span>
                            </div>
                        </div>
                    )}
                </div>
                
                {/* Add more widgets here in the future if needed */}
                <div style={{ flex: 2 }}></div>
            </div>
        </div>
    );
};

export default Dashboard;
